SELECT DISTINCT dataset_id
FROM city_datasets
ORDER BY dataset_id;

SELECT dataset_name
FROM city_datasets
WHERE city_id = 0;

SELECT COUNT(dataset_id) AS dataset_count
FROM city_datasets
WHERE city_id = 1;

SELECT export_id
FROM data_export_history
WHERE export_date BETWEEN '2023-05-01' AND '2023-05-03';

SELECT city_name
FROM cities
WHERE city_id = (SELECT capital_city_id FROM countries WHERE country_name = 'Austria');
